// app/utils/HtmlSanitizer.scala
package utils

import org.jsoup.Jsoup
import org.jsoup.safety.Safelist

object HtmlSanitizer {

  private val safelist: Safelist = Safelist.relaxed()
    .addTags("p", "br", "strong", "em", "b", "i", "u", "s", "blockquote", "pre", "code", "h1", "h2", "h3", "h4", "h5", "h6", "hr")
    .addTags("a", "img", "ul", "ol", "li", "table", "thead", "tbody", "tr", "th", "td")
    .addAttributes("a", "href", "title", "rel", "target")
    .addAttributes("img", "src", "alt", "title", "width", "height")
    .addAttributes("td", "colspan", "rowspan")
    .addAttributes("th", "colspan", "rowspan")
    .addProtocols("a", "href", "http", "https", "mailto")
    .addProtocols("img", "src", "http", "https")
    .addEnforcedAttribute("a", "rel", "nofollow noopener noreferrer")
    .addEnforcedAttribute("a", "target", "_blank")

  def sanitize(untrustedHtml: String): String = {
    Jsoup.clean(untrustedHtml, safelist)
  }
}